import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.ufzXw1qY.js";const p=JSON.parse('{"title":"Software 3.0 & Neural-Bus Doctrine","description":"The architectural doctrine for evented, agentic, issue-centric, bus-driven OpenSIN systems.","frontmatter":{"title":"Software 3.0 & Neural-Bus Doctrine","description":"The architectural doctrine for evented, agentic, issue-centric, bus-driven OpenSIN systems."},"headers":[],"relativePath":"best-practices/software-3.0-neural-bus.md","filePath":"best-practices/software-3.0-neural-bus.md"}'),n={name:"best-practices/software-3.0-neural-bus.md"};function s(o,e,l,h,u,d){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="software-3-0-neural-bus-doctrine" tabindex="-1">Software 3.0 &amp; Neural-Bus Doctrine <a class="header-anchor" href="#software-3-0-neural-bus-doctrine" aria-label="Permalink to &quot;Software 3.0 &amp; Neural-Bus Doctrine&quot;">​</a></h1><blockquote><p><strong>RULE:</strong> We are not building isolated apps anymore. We are building an evented organism: agents, workflows, repos, UI surfaces, and operators connected through explicit signals, issue state, and recoverable automation.</p></blockquote><hr><h2 id="_1-what-software-3-0-means-here" tabindex="-1">1. What “Software 3.0” Means Here <a class="header-anchor" href="#_1-what-software-3-0-means-here" aria-label="Permalink to &quot;1. What “Software 3.0” Means Here&quot;">​</a></h2><p>Software 3.0 in OpenSIN means:</p><ul><li>issue-centric work, not hidden local intention</li><li>agentic execution, not single-process heroics</li><li>event-driven coordination, not brittle manual chaining</li><li>observable state, not invisible automation</li><li>modular capabilities, not monolithic dependency traps</li></ul><p>The “Neural Bus” is the idea that meaningful state changes propagate through the ecosystem like signals in a nervous system.</p><hr><h2 id="_2-the-bus-is-conceptual-and-concrete" tabindex="-1">2. The Bus Is Conceptual and Concrete <a class="header-anchor" href="#_2-the-bus-is-conceptual-and-concrete" aria-label="Permalink to &quot;2. The Bus Is Conceptual and Concrete&quot;">​</a></h2><p>It is <strong>conceptual</strong> because it describes how all parts of the fleet should think about coordination. It is <strong>concrete</strong> because it appears in:</p><ul><li>GitHub issues and PRs</li><li>n8n workflows</li><li>agent events and heartbeats</li><li>webhooks</li><li>notifications</li><li>dashboards and logs</li></ul><hr><h2 id="_3-event-centric-thinking" tabindex="-1">3. Event-Centric Thinking <a class="header-anchor" href="#_3-event-centric-thinking" aria-label="Permalink to &quot;3. Event-Centric Thinking&quot;">​</a></h2><p>Design systems around meaningful events:</p><ul><li>issue created</li><li>task dispatched</li><li>agent started</li><li>agent completed</li><li>workflow failed</li><li>deployment published</li><li>alert raised</li><li>approval granted</li></ul><h3 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Polling disconnected state everywhere creates lag, duplication, and confusion. Events compress coordination.</p><hr><h2 id="_4-state-must-be-recoverable" tabindex="-1">4. State Must Be Recoverable <a class="header-anchor" href="#_4-state-must-be-recoverable" aria-label="Permalink to &quot;4. State Must Be Recoverable&quot;">​</a></h2><p>Any important workflow should be resumable from durable state:</p><ul><li>issue state</li><li>repo state</li><li>workflow execution history</li><li>persisted task/session identifiers</li><li>logs/evidence</li></ul><h3 id="why-1" tabindex="-1">Why <a class="header-anchor" href="#why-1" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>If a VM restarts or an agent dies, the system should resume from signal history, not human memory.</p><hr><h2 id="_5-human-operator-as-high-privilege-node" tabindex="-1">5. Human Operator as High-Privilege Node <a class="header-anchor" href="#_5-human-operator-as-high-privilege-node" aria-label="Permalink to &quot;5. Human Operator as High-Privilege Node&quot;">​</a></h2><p>The operator is part of the bus, but should not be used as glue for routine work. Escalate only when:</p><ul><li>permissions are truly required</li><li>destructive approval is needed</li><li>a real blocker survives automation</li></ul><h3 id="why-2" tabindex="-1">Why <a class="header-anchor" href="#why-2" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>The user is the final authority, not the default transport layer.</p><hr><h2 id="_6-what-the-neural-bus-rejects" tabindex="-1">6. What the Neural-Bus Rejects <a class="header-anchor" href="#_6-what-the-neural-bus-rejects" aria-label="Permalink to &quot;6. What the Neural-Bus Rejects&quot;">​</a></h2><ul><li>hidden local-only state</li><li>undocumented side channels</li><li>one-off scripts with no tracker link</li><li>manual handoffs that should be evented</li><li>“done” messages with no durable artifact</li></ul><hr><h2 id="_7-architecture-consequences" tabindex="-1">7. Architecture Consequences <a class="header-anchor" href="#_7-architecture-consequences" aria-label="Permalink to &quot;7. Architecture Consequences&quot;">​</a></h2><p>A proper Neural-Bus system implies:</p><ul><li>issue-first execution</li><li>branch/PR traceability</li><li>workflow/agent status visibility</li><li>durable evidence</li><li>explicit contracts between modules</li><li>bounded retries and escalation</li></ul><hr><h2 id="_8-final-rule" tabindex="-1">8. Final Rule <a class="header-anchor" href="#_8-final-rule" aria-label="Permalink to &quot;8. Final Rule&quot;">​</a></h2><p><strong>Software 3.0 is software that can think in public, recover from interruption, and coordinate through evidence instead of hope.</strong> If the system depends on one human remembering what happened, it is not Software 3.0.</p><hr><p><em>Last updated:</em> 2026-04-10<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>Self-Hosted</strong></td><td>0.0</td><td>OCI VM — KEINE Cloud-Dienste</td></tr><tr><td><strong>Annahmen-Verbot</strong></td><td>-5.0</td><td>KEINE Diagnose ohne Beweis</td></tr></tbody></table>',44)])])}const b=t(n,[["render",s]]);export{p as __pageData,b as default};
